  "sentences": [
    {
      "text": "我的中文比他的中文流利。",
      "pinyin": "Wǒ de zhōngwén bǐ tā de zhōngwén liúlì.",
      "pinyin_numeric": "wo3 de0 zhong1wen2 bi3 ta1 de0 zhong1wen2 liu2li4",
      "translation_en": "My Chinese is more fluent than his Chinese.",
      "translation_ko": "제 중국어가 그의 중국어보다 유창합니다."
    },
    {
      "text": "這個句子比那個句子清楚。",
      "pinyin": "Zhège jùzi bǐ nàge jùzi qīngchu.",
      "pinyin_numeric": "zhe4ge0 ju4zi0 bi3 na4ge0 ju4zi0 qing1chu0",
      "translation_en": "This sentence is clearer than that sentence.",
      "translation_ko": "이 문장이 그 문장보다 더 명확합니다."
    },
    {
      "text": "今天的重點比昨天的重點多。",
      "pinyin": "Jīntiān de zhòngdiǎn bǐ zuótiān de zhòngdiǎn duō.",
      "pinyin_numeric": "jin1tian1 de0 zhong4dian3 bi3 zuo2tian1 de0 zhong4dian3 duo1",
      "translation_en": "Today's key points are more than yesterday's key points.",
      "translation_ko": "오늘의 핵심 포인트가 어제보다 더 많습니다."
    },
    {
      "text": "我的弱點比他的弱點少。",
      "pinyin": "Wǒ de ruòdiǎn bǐ tā de ruòdiǎn shǎo.",
      "pinyin_numeric": "wo3 de0 ruo4dian3 bi3 ta1 de0 ruo4dian3 shao3",
      "translation_en": "My weaknesses are fewer than his weaknesses.",
      "translation_ko": "제 약점이 그의 약점보다 적습니다."
    },
    {
      "text": "這個答案比那個答案好。",
      "pinyin": "Zhège dá'àn bǐ nàge dá'àn hǎo.",
      "pinyin_numeric": "zhe4ge0 da2an4 bi3 na4ge0 da2an4 hao3",
      "translation_en": "This answer is better than that answer.",
      "translation_ko": "이 답변이 그 답변보다 더 좋습니다."
    },
    {
      "text": "他改正的錯誤比我改正的錯誤多。",
      "pinyin": "Tā gǎizhèng de cuòwù bǐ wǒ gǎizhèng de cuòwù duō.",
      "pinyin_numeric": "ta1 gai3zheng4 de0 cuo4wu4 bi3 wo3 gai3zheng4 de0 cuo4wu4 duo1",
      "translation_en": "He corrected more mistakes than I corrected.",
      "translation_ko": "그가 고친 실수가 제가 고친 실수보다 더 많습니다."
    },
    {
      "text": "再試一次比第一次流利。",
      "pinyin": "Zài shì yī cì bǐ dì yī cì liúlì.",
      "pinyin_numeric": "zai4 shi4 yi1 ci4 bi3 di4 yi1 ci4 liu2li4",
      "translation_en": "Trying again is more fluent than the first time.",
      "translation_ko": "다시 시도하는 것이 처음보다 더 유창합니다."
    },
    {
      "text": "這個重點比那個重點重要。",
      "pinyin": "Zhège zhòngdiǎn bǐ nàge zhòngdiǎn zhòngyào.",
      "pinyin_numeric": "zhe4ge0 zhong4dian3 bi3 na4ge0 zhong4dian3 zhong4yao4",
      "translation_en": "This key point is more important than that key point.",
      "translation_ko": "이 핵심 포인트가 그 핵심 포인트보다 더 중요합니다."
    },
    {
      "text": "他的句子比我的句子清楚。",
      "pinyin": "Tā de jùzi bǐ wǒ de jùzi qīngchu.",
      "pinyin_numeric": "ta1 de0 ju4zi0 bi3 wo3 de0 ju4zi0 qing1chu0",
      "translation_en": "His sentences are clearer than my sentences.",
      "translation_ko": "그의 문장이 제 문장보다 더 명확합니다."
    },
    {
      "text": "我的弱點比他的弱點多。",
      "pinyin": "Wǒ de ruòdiǎn bǐ tā de ruòdiǎn duō.",
      "pinyin_numeric": "wo3 de0 ruo4dian3 bi3 ta1 de0 ruo4dian3 duo1",
